import{_ as a,o as r,c as e,ag as l}from"./chunks/framework.CTpQozEL.js";const p=JSON.parse('{"title":"위협 모델에 기여하기","description":"OpenClaw 위협 모델에 기여하는 방법","frontmatter":{"title":"위협 모델에 기여하기","description":"OpenClaw 위협 모델에 기여하는 방법"},"headers":[],"relativePath":"security/CONTRIBUTING-THREAT-MODEL.md","filePath":"security/CONTRIBUTING-THREAT-MODEL.md","lastUpdated":null}'),o={name:"security/CONTRIBUTING-THREAT-MODEL.md"};function i(n,t,d,s,h,u){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="openclaw-위협-모델에-기여하기" tabindex="-1">OpenClaw 위협 모델에 기여하기 <a class="header-anchor" href="#openclaw-위협-모델에-기여하기" aria-label="Permalink to &quot;OpenClaw 위협 모델에 기여하기&quot;">​</a></h1><p>OpenClaw를 더 안전하게 만드는 데 도움을 주셔서 감사합니다. 이 위협 모델은 살아있는 문서이며 보안 전문가가 아니더라도 누구나 기여를 환영합니다.</p><h2 id="기여-방법" tabindex="-1">기여 방법 <a class="header-anchor" href="#기여-방법" aria-label="Permalink to &quot;기여 방법&quot;">​</a></h2><h3 id="위협-추가" tabindex="-1">위협 추가 <a class="header-anchor" href="#위협-추가" aria-label="Permalink to &quot;위협 추가&quot;">​</a></h3><p>우리가 다루지 않은 공격 벡터나 위험을 발견하셨나요? <a href="https://github.com/openclaw/trust/issues" target="_blank" rel="noreferrer">openclaw/trust</a>에 이슈를 열고 자신의 말로 설명하십시오. 프레임워크를 알거나 모든 필드를 채울 필요가 없습니다 — 시나리오만 설명하면 됩니다.</p><p><strong>포함하면 도움이 되는 것 (필수 아님):</strong></p><ul><li>공격 시나리오와 악용 방법</li><li>OpenClaw의 영향 받는 부분 (CLI, 게이트웨이, 채널, ClawHub, MCP 서버 등)</li><li>얼마나 심각하다고 생각하는지 (낮음 / 중간 / 높음 / 심각)</li><li>관련 연구, CVE 또는 실제 사례에 대한 링크</li></ul><p>검토 중에 ATLAS 매핑, 위협 ID 및 위험 평가를 처리할 것입니다. 해당 세부 정보를 포함하고 싶으시면 환영하지만 필수는 아닙니다.</p><blockquote><p><strong>이것은 위협 모델에 추가하기 위한 것이며 실제 취약점을 보고하기 위한 것이 아닙니다.</strong> 악용 가능한 취약점을 발견한 경우 책임감 있는 공개 지침은 <a href="https://trust.openclaw.ai" target="_blank" rel="noreferrer">Trust 페이지</a>를 참조하십시오.</p></blockquote><h3 id="완화-방법-제안" tabindex="-1">완화 방법 제안 <a class="header-anchor" href="#완화-방법-제안" aria-label="Permalink to &quot;완화 방법 제안&quot;">​</a></h3><p>기존 위협을 해결하는 방법에 대한 아이디어가 있으신가요? 위협을 참조하는 이슈 또는 PR을 여십시오. 유용한 완화 방법은 구체적이고 실행 가능합니다 — 예를 들어 &quot;게이트웨이에서 발신자당 분당 10개 메시지 속도 제한&quot;이 &quot;속도 제한 구현&quot;보다 좋습니다.</p><h3 id="공격-체인-제안" tabindex="-1">공격 체인 제안 <a class="header-anchor" href="#공격-체인-제안" aria-label="Permalink to &quot;공격 체인 제안&quot;">​</a></h3><p>공격 체인은 여러 위협이 현실적인 공격 시나리오로 결합되는 방법을 보여줍니다. 위험한 조합이 보이면 단계와 공격자가 어떻게 결합할지 설명하십시오. 공격이 실제로 어떻게 전개되는지에 대한 짧은 이야기가 공식 템플릿보다 더 가치 있습니다.</p><h3 id="기존-내용-수정-또는-개선" tabindex="-1">기존 내용 수정 또는 개선 <a class="header-anchor" href="#기존-내용-수정-또는-개선" aria-label="Permalink to &quot;기존 내용 수정 또는 개선&quot;">​</a></h3><p>오타, 명확화, 오래된 정보, 더 나은 예시 — PR 환영, 이슈 필요 없음.</p><h2 id="사용하는-것" tabindex="-1">사용하는 것 <a class="header-anchor" href="#사용하는-것" aria-label="Permalink to &quot;사용하는 것&quot;">​</a></h2><h3 id="mitre-atlas" tabindex="-1">MITRE ATLAS <a class="header-anchor" href="#mitre-atlas" aria-label="Permalink to &quot;MITRE ATLAS&quot;">​</a></h3><p>이 위협 모델은 프롬프트 주입, 도구 남용, 에이전트 악용과 같은 AI/ML 위협을 위해 특별히 설계된 프레임워크인 <a href="https://atlas.mitre.org/" target="_blank" rel="noreferrer">MITRE ATLAS</a> (AI 시스템을 위한 적대적 위협 환경)를 기반으로 합니다. 기여하기 위해 ATLAS를 알 필요는 없습니다 — 검토 중에 제출물을 프레임워크에 매핑합니다.</p><h3 id="위협-id" tabindex="-1">위협 ID <a class="header-anchor" href="#위협-id" aria-label="Permalink to &quot;위협 ID&quot;">​</a></h3><p>각 위협은 <code>T-EXEC-003</code> 같은 ID를 받습니다. 카테고리는:</p><table tabindex="0"><thead><tr><th>코드</th><th>카테고리</th></tr></thead><tbody><tr><td>RECON</td><td>정찰 - 정보 수집</td></tr><tr><td>ACCESS</td><td>초기 액세스 - 진입 획득</td></tr><tr><td>EXEC</td><td>실행 - 악의적 작업 실행</td></tr><tr><td>PERSIST</td><td>지속성 - 액세스 유지</td></tr><tr><td>EVADE</td><td>방어 회피 - 탐지 회피</td></tr><tr><td>DISC</td><td>검색 - 환경에 대한 학습</td></tr><tr><td>EXFIL</td><td>유출 - 데이터 도용</td></tr><tr><td>IMPACT</td><td>영향 - 손상 또는 중단</td></tr></tbody></table><p>ID는 검토 중에 관리자가 할당합니다. 직접 선택할 필요가 없습니다.</p><h3 id="위험-수준" tabindex="-1">위험 수준 <a class="header-anchor" href="#위험-수준" aria-label="Permalink to &quot;위험 수준&quot;">​</a></h3><table tabindex="0"><thead><tr><th>수준</th><th>의미</th></tr></thead><tbody><tr><td><strong>심각</strong></td><td>전체 시스템 손상, 또는 높은 가능성 + 심각한 영향</td></tr><tr><td><strong>높음</strong></td><td>상당한 피해 가능성, 또는 중간 가능성 + 심각한 영향</td></tr><tr><td><strong>중간</strong></td><td>보통 위험, 또는 낮은 가능성 + 높은 영향</td></tr><tr><td><strong>낮음</strong></td><td>가능성 낮고 영향 제한적</td></tr></tbody></table><p>위험 수준이 확실하지 않으면 영향을 설명하면 평가하겠습니다.</p><h2 id="검토-프로세스" tabindex="-1">검토 프로세스 <a class="header-anchor" href="#검토-프로세스" aria-label="Permalink to &quot;검토 프로세스&quot;">​</a></h2><ol><li><strong>분류</strong> — 48시간 이내에 새 제출물을 검토합니다</li><li><strong>평가</strong> — 실현 가능성을 확인하고 ATLAS 매핑 및 위협 ID를 할당하고 위험 수준을 검증합니다</li><li><strong>문서화</strong> — 모든 것이 형식화되고 완전한지 확인합니다</li><li><strong>병합</strong> — 위협 모델 및 시각화에 추가됩니다</li></ol><h2 id="리소스" tabindex="-1">리소스 <a class="header-anchor" href="#리소스" aria-label="Permalink to &quot;리소스&quot;">​</a></h2><ul><li><a href="https://atlas.mitre.org/" target="_blank" rel="noreferrer">ATLAS 웹사이트</a></li><li><a href="https://atlas.mitre.org/techniques/" target="_blank" rel="noreferrer">ATLAS 기법</a></li><li><a href="https://atlas.mitre.org/studies/" target="_blank" rel="noreferrer">ATLAS 사례 연구</a></li><li><a href="/openclaw-docs-ko/security/THREAT-MODEL-ATLAS">OpenClaw 위협 모델</a></li></ul><h2 id="연락처" tabindex="-1">연락처 <a class="header-anchor" href="#연락처" aria-label="Permalink to &quot;연락처&quot;">​</a></h2><ul><li><strong>보안 취약점:</strong> 보고 지침은 <a href="https://trust.openclaw.ai" target="_blank" rel="noreferrer">Trust 페이지</a> 참조</li><li><strong>위협 모델 질문:</strong> <a href="https://github.com/openclaw/trust/issues" target="_blank" rel="noreferrer">openclaw/trust</a>에 이슈 열기</li><li><strong>일반 채팅:</strong> Discord #security 채널</li></ul><h2 id="인정" tabindex="-1">인정 <a class="header-anchor" href="#인정" aria-label="Permalink to &quot;인정&quot;">​</a></h2><p>위협 모델에 기여한 분들은 위협 모델 감사의 말, 릴리스 노트 및 중요한 기여에 대한 OpenClaw 보안 명예의 전당에서 인정받습니다.</p>',33)])])}const b=a(o,[["render",i]]);export{p as __pageData,b as default};
